var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"얍.","JPN":"やあっ。","ENG":"Yap.","TWN":"嘿。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L5_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":" 얍.","JPN":" やあっ。","ENG":" Yap.","TWN":"嘿。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L7_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":" 얍.","JPN":" やあっ。","ENG":" Yap.","TWN":"嘿。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L9_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"가, 강시도 아니고 어떻게 저렇게 뛰는 거야…….","JPN":"きょ、キョンシーでもないのに、どうやったらあんなに飛べるの……？","ENG":"Does she have springs for her legs or something...?","TWN":"她不是殭屍吧？怎麼那樣跳……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"포, 포기하지 마세요. 히로세 씨.","JPN":"あ、諦めないでください。廣瀬さん。","ENG":"D-don't give up, Ms. Hirose.","TWN":"別放棄，廣瀨。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"저 아이만 붙잡으면 오늘 저녁은 풍족하게……","JPN":"あの子さえ捕まえれば、今日の夕食は贅沢に……","ENG":"We just need to capture her, and we'll be having a feast for dinn–","TWN":"只要抓住那她，今晚就能隨心所欲地……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"미, 민서 양?! 정신 차려요!","JPN":"ひ、ヒミコさん！？　しっかりしてください！","ENG":"M-Minseo?! Are you okay?!","TWN":"李旼序？你醒醒！"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"무얼 숨기랴. 크레데레는 술래잡기로 지구 반대편까지 도망친 적이 있습니다.","JPN":"何を隠そう。クレデレは鬼ごっこで地球の反対側まで逃げた経験があるんです。","ENG":"No skeletons in this closet. Credere has a record of running to the opposite side of the earth while playing tag.","TWN":"克蕾妲莉沒有秘密。克蕾妲莉曾經玩捉迷藏時逃到地球的另一端。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"그런 크레데레를 붙잡으려 하다니 아직 천년은 이르군요.","JPN":"そんなクレデレを捕まえようとするなんて、まだ千年は早いですね。","ENG":"You are much too inexperienced to capture Credere.","TWN":"想要抓住這樣的克蕾妲莉，你還早一萬年呢。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"다음번에는 각성이라도 해서 오시길. 그럼 아디오스-.","JPN":"次回は覚醒でもしてから来てください。では、アディオスー","ENG":"I suggest you find a way to reach your awakening before finding me again. Adios.","TWN":"下次等你覺醒後再來找克蕾妲莉吧。那就再見囉。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L21_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"아, 안 돼…….","JPN":"だ、ダメ……","ENG":"N-no...","TWN":"噢，不……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"돌아와. 내 고기 반찬-!!","JPN":"戻ってきて。私のお肉ー！！","ENG":"Come back, my meat for dinner!!","TWN":"回來啊，我的肉——!!"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"윽.","JPN":"ぐっ。","ENG":"Ngh.","TWN":"唔。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"이런. 기록 경신에는 성공했지만 여기까지인가요.","JPN":"やれやれ。記録更新には成功しましたけど、ここまでですか。","ENG":"Oh, dear. Credere succeeded in achieving a new record, but it seems like this is where it ends.","TWN":"雖然刷新了記錄，但好像沒辦法繼續下去了。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"발 상태는…","JPN":"足の状態は……","ENG":"Credere's foot is...","TWN":"腳的狀態……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":" 더는 무리일지도.","JPN":" もう無理かも。","ENG":" not in a good state.","TWN":"再這樣下去可能會撐不住。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"아아. 이렇게 허무하게 가는구나-.","JPN":"ああ。こんな虚しく逝くのかー","ENG":"Ahh. So this is how it ends.","TWN":"啊～就這樣空虛地離開嗎？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"크레데레. 죽다.","JPN":"クレデレ。死す。","ENG":"Credere, deceased.","TWN":"克蕾妲莉，倒下。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"깨꼬닥.","JPN":"バタリ。","ENG":"Bleh.","TWN":"倒。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"저기…….","JPN":"あの……","ENG":"Hey...","TWN":"那個……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"깜짝야.","JPN":"びっくりした。","ENG":"Oh, my.","TWN":"嚇我一跳。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L41_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"괜찮으신가요? 거리 한복판에 쓰러져 계시길래.","JPN":"大丈夫ですか？　道の真ん中に倒れているんですもの。","ENG":"Are you all right? You were on the ground in the middle of the street.","TWN":"沒事吧？看到你倒在街道中央。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"문제없습니다. 크레데레는 넘어져도 일어나는 오뚝이인지라.","JPN":"問題ありません。クレデレは倒れても起き上がるダルマですので。","ENG":"All good. Credere is like a roly-poly, she will always roll back up.","TWN":"沒問題的。克蕾妲莉就像不倒翁一樣，即使倒下也會重新站起來。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"도움.","JPN":"助けて。","ENG":"Help.","TWN":"幫我。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"걱정 마세요. 다친 사람을 치유하는 건 제 특기거든요.","JPN":"心配しないでくださいね。怪我人を治癒するのは私得意なんですよ。","ENG":"Don't worry. I'm skilled at treating the injured.","TWN":"別擔心，我的專長就是治療別人。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"방울방울, 푹신푹신 해져라~.","JPN":"ぽつりぽつり、ふわふわになれ～","ENG":"Bubble bubble, become soft again!","TWN":"滴答滴答，變得軟軟的～"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"…음?","JPN":"……ん？","ENG":"...Mm?","TWN":"……嗯？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"크레데레 선수. 부활~.","JPN":"クレデレ選手。復活～","ENG":"Credere comes back to life!","TWN":"克蕾妲莉選手。復活——"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L5_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"와아-. 다리가 나아서 다행이에요.","JPN":"わあー足が治ってよかったですね。","ENG":"Yay! I'm glad your legs are better.","TWN":"哇啊——，你的腿好了，真是太好了。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"이 근방은 수배령이 내려졌으니까 저를 따라와 주세요.","JPN":"この辺りは指名手配が出ていますから、私について来てください。","ENG":"This area is full of bounty hunters, so please follow me.","TWN":"這附近發佈了通緝令，請跟我來吧。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"유감이지만 크레데레는 항구로 가야 합니다. 유피와 만나기로 약속했거든요.","JPN":"残念ですけど、クレデレは港に行かないとダメです。ユピと会う約束をしました。","ENG":"Credere is afraid that she has to go to the port. She promised Yuppie to meet her there.","TWN":"很遺憾，克蕾妲莉必須去港口。克蕾妲莉和悠菲有個約定。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"신뢰의 아이콘이 약속을 어길 수는 없습니다.","JPN":"信頼の象徴が約束を破るわけにはいかないです。","ENG":"An icon of trust cannot break a promise.","TWN":"信賴的象徵是不能違背約定的。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"안 돼요! 부단장님이 민간인분들의 대피를 부탁하셨는걸요.","JPN":"ダメです！　副団長に民間人を避難させるように頼まれたんです。","ENG":"No! The deputy asked me to evacuate the civilians.","TWN":"不行！副團長拜託我疏散平民呢。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"부상까지 입으셨던 분을 보내 드릴 수는 없어요.","JPN":"怪我までしている方を行かせるわけにはいきませんよ。","ENG":"I cannot let an injured civilian leave.","TWN":"不能讓受傷的人去冒險……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"무얼 숨기랴. 크레데레는 뒤끝이 없는 걸로 명성이 자자합니다.","JPN":"何を隠そう。クレデレは後腐れないことで有名です。","ENG":"No skeletons in this closet. Credere is known for not holding a grudge.","TWN":"克蕾妲莉沒有祕密，克蕾妲莉可是翻臉跟翻書一樣快。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"과거의 은혜 따윈 잊어버린 지 오래.","JPN":"過去の恩なんてとっくに忘れました。","ENG":"Credere has forgotten about the favors of the past.","TWN":"你的救命之恩克蕾妲莉轉眼就會忘記。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L15_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"당장 비키지 않으면 크레데레가 얼마나 무서운 사람인지 알게 될 겁니다.","JPN":"今すぐ退かないと、クレデレがどれほど怖い人なのかわかるようになるでしょう。","ENG":"Move now, or you will witness the true terror of Credere.","TWN":"如果你現在不讓開，你會知道克蕾妲莉有多可怕。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"테, 테이저건을 들이미셔도 안 되는 건 안 돼요!","JPN":"て、テーザーガンを突きつけてもダメなものはダメです！","ENG":"Y-you can point a taser at me, but I can't let you leave!","TWN":"就、就算拿槍對著我也沒用！"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"부단장님이 저한테…","JPN":"副団長が私に……","ENG":"Deputy left me with–","TWN":"副團長說……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":" 어라?","JPN":" あれ？","ENG":" Huh?","TWN":"咦？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"그 목걸이는…….","JPN":"そのネックレスは……","ENG":"That necklace is...","TWN":"那條項鍊是……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"눈썰미가 좋으시군요. 멋쟁이 해적의 필수품인 시그마 선장님표 특제 목걸이입니다.","JPN":"目が高いですね。オシャレ海賊の必需品であるシグマ船長の特製ネックレスです。","ENG":"So you've noticed. This is Captain Sigma's special necklace, an essential accessory for cool pirates.","TWN":"你很有眼光。這是帥氣海盜必備的西格瑪船長特製項鍊。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L24_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"상품으로서의 가치는 없지만, 사회생활을 위해 착용은 필수죠.","JPN":"商品としての価値はないですが、社会人としてやっていく上で着用は必須なんです。","ENG":"It has no value as a product, but one is required to wear it for social reasons.","TWN":"雖然沒有商品價值，但為了社交生活，佩戴是必須的。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"해적…? 시그마 선장님…?","JPN":"海賊……？　シグマ船長……？","ENG":"Pirate...? Captain Sigma...?","TWN":"海盜……？西格瑪船長……？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"와, 시그마 해적단원이셨군요! 저도 선장님의 선원이에요, 얼!","JPN":"わあ、シグマ海賊団の一員だったのですね！　私も船長の船員です、ARRR！","ENG":"Oh! You're a crew mate of the Sigma Pirates! I'm a crew member too, yarr!","TWN":"哇，原來你是西格瑪海盜團的同伴啊！我也是船長的船員，呀呵！"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L27_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"세일러복을 입고 계시길래 설마 싶었는데, 정말 해적이셨군요?","JPN":"セーラー服を着ているのでもしかしてと思ったんですけど、本当に海賊だったのですね？","ENG":"I thought maybe, after seeing your sailor suit, but you really are a pirate!","TWN":"看到你穿著水手服，原來真的是海盜啊？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"무얼 숨기랴. 크레데레는 잔혹하고 무자비한 해적이 맞습니다.","JPN":"何を隠そう。クレデレは残酷かつ無慈悲な海賊です。","ENG":"No skeletons in this closet. Credere is indeed a cruel and merciless pirate.","TWN":"克蕾妲莉沒有祕密。克蕾妲莉確實是殘酷無情的海盜。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"침식체로 따지면 거진 10급 침식체라 할 수 있죠.","JPN":"侵食体に例えると、ほぼレベル第10種侵食体とも言えるでしょう。","ENG":"In C.O. standards, Credere is a Category 10 C.O.","TWN":"如果要說侵蝕體的話，可以說是接近10類的侵蝕體。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"헉. 외발 해적님은 엄청 대단하신 분이셨군요.","JPN":"はっ。片足の海賊さんは本当にすごい方だったんですね。","ENG":"Wow. You're a big deal, Ms. One-Legged Pirate.","TWN":"哇。獨腳海盜好厲害喔。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"항구에 가시려는 건… 설마 보물을 찾기 위해서인가요?","JPN":"港に行くってことは……まさかお宝を探すためなんですか？","ENG":"Are you heading to the port... to find treasure?","TWN":"你現在要去港口……難道是為了尋寶嗎？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"그렇습니다. 시그마 해적단은 지금 절찬리에 보물을 찾는 중이죠.","JPN":"そうです。シグマ海賊団はただいまお宝探しの真っ最中です。","ENG":"Indeed. The Sigma Pirates are on the hunt for treasure.","TWN":"沒錯。西格瑪海盜團現在正在如火如荼地尋找寶藏。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"보물 자체에는 관심 없지만, 크레데레는 동료를 버리고 혼자 도망치진 않습니다.","JPN":"お宝自体には興味ないんですけど、クレデレは仲間を捨てて一人で逃げたりしません。","ENG":"Credere has no interest in the treasure itself, but Credere does not abandon her companion.","TWN":"雖然對寶藏本身沒興趣，但克蕾妲莉不會拋棄同伴獨自逃跑。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"이건?","JPN":"これは？","ENG":"What is this?","TWN":"這是……？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"후후. 이 근방의 약도예요. 어차피 저는 봐도 잘 모르거든요.","JPN":"ふふ。この辺りの地図です。どうせ私は見てもよくわからないですから。","ENG":"Hu hu. It's a map of this area. I wouldn't know how to read it, anyway.","TWN":"嘻嘻。這是附近的地圖。反正我也不大懂。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"부단장님도 해적을 막으라는 말은 없었으니 괜찮지 않을까요?","JPN":"副団長も海賊を止めろとは言ってなかったですし、大丈夫じゃないですか？","ENG":"Deputy never told me to stop pirates, so I think this should be fine.","TWN":"副團長也沒交代海盜的事情，這樣應該沒問題吧？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"감사합니다. 이 은혜는 반드시 갚겠, 꾸벅.","JPN":"ありがとうございます。この恩は忘れま、ペコリ。","ENG":"Thank you. Credere will remember this, bow.","TWN":"謝謝。克蕾妲莉一定會報答這份恩情，鞠躬——"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"별거 아니에요. 시그마 선장님한테 안부 전해주, 꾸벅?","JPN":"どういたしまして。シグマ船長によろしく伝えてくだ、ペコリ？","ENG":"It's nothing. Please tell Captain Sigma I said hi, bow?","TWN":"沒什麼。請代我向西格瑪船長問好，鞠躬？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"저, 저기 있다! 민서 양 찾았어요!","JPN":"い、いた！　ヒミコさん、見つけました！","ENG":"Th-there she is! I found her, Minseo!","TWN":"在、在那邊！找到了，李旼序！"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"고기 반찬. 우리의 고기 반찬……!!","JPN":"お肉。ヒミコたちのお肉……！！","ENG":"Meat! Our precious meat dish...!","TWN":"肉，我們的肉……!!"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"이런. 아무래도 헤어져야 할 시간인 것 같군요.","JPN":"おっと。どうやらお別れの時間みたいですね。","ENG":"Oh, dear. It is time for my departure.","TWN":"啊。看來是時候分別了。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"크레데레의 이름은 크레데레입니다. 그쪽 이름은?","JPN":"クレデレの名前はクレデレです。そちらのお名前は？","ENG":"Credere's name is Credere. And you are?","TWN":"克蕾妲莉的名字就是克蕾妲莉。你叫什麼名字？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"조디악 나이츠의 물병자리의 기사. 에리어스라고 해요.","JPN":"ゾディアックナイツの水瓶座の騎士、アリウスです。","ENG":"I am Arius, the Knight of Aquarius of the Zodiac Knights.","TWN":"我是十二宮騎士團的水瓶座騎士，埃里奧斯。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"꼭 보물을 찾길 빌게요. 크레데레 씨.","JPN":"お宝を見つけられたらいいですね、クレデレさん。","ENG":"I hope you find your treasure, Credere.","TWN":"我會祈禱你找到寶藏的，克蕾妲莉。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"걱정 마시죠, 크레데레는 영원불멸한 신뢰의 아이콘입니다.","JPN":"心配しないでください、クレデレは永遠不滅の信頼の象徴です。","ENG":"Of course. Credere is the immortal icon of trust.","TWN":"別擔心，克蕾妲莉是永恆不滅的信賴的象徵。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"그럼 아디오스-.","JPN":"では、アディオス。","ENG":"Adios.","TWN":"那麼拜拜——"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"또 시작이에요, 민서 양! 저 꼬맹이가 한 발로 뛰기 시작했다고요!","JPN":"またです、ヒミコさん！　あのチビちゃん、また片足で飛び始めましたよ！","ENG":"She's doing it again, Minseo! She started running on one foot again!","TWN":"又開始了，李旼序！她又開始單腳跳了！"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_05"},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"한 발… 한 발인데 왜 저희보다 빠른 건가요…….","JPN":"片足……片足なのにどうしてヒミコたちより速いんですか……","ENG":"One foot... How is she faster than us on one foot...?","TWN":"單腳……單腳跳為什麼比我們還快……"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_05"},{"id":"L11_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"후후. 선장님이 부러워요. 저런 멋진 친구분을 사귀다니.","JPN":"ふふ。船長がうらやましいです。あんな素敵な友だちがいるなんて。","ENG":"Hu hu. I'm envious of the captain to have such an amazing friend.","TWN":"呼呼。真羡慕船長。能交到這麼棒的朋友。"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"다음에는 저도 같이 놀 수 있을까요?","JPN":"今度は私も一緒に交ぜてもらえるんでしょうかね？","ENG":"Maybe next time, I'll be able to join.","TWN":"下次我也能一起玩嗎……？"},"stage":{"bg":"TEHERANRO_NIGHT","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};